import requests
import time
from typing import Any, Dict, Optional

BASE_URL = 'https://api.example.com/v1'
DEFAULT_TIMEOUT = 30


class APIClient:
    def __init__(self, api_key: str, base_url: str = BASE_URL):
        self.api_key = api_key
        self.base_url = base_url
        self.session = requests.Session()
        self.session.headers.update({
            'Authorization': f'Bearer {api_key}',
            'Content-Type': 'application/json',
            'Accept': 'application/json',
        })

    def _request(
        self,
        method: str,
        endpoint: str,
        payload: Optional[Dict[str, Any]] = None,
        params: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        url = f'{self.base_url}{endpoint}'
        response = self.session.request(
            method,
            url,
            json=payload,
            params=params,
            timeout=DEFAULT_TIMEOUT,
        )
        response.raise_for_status()
        return response.json()

    def get_user(self, user_id: int) -> Dict[str, Any]:
        return self._request('GET', f'/users/{user_id}')

    def create_resource(self, data: Dict[str, Any]) -> Dict[str, Any]:
        return self._request('POST', '/resources', payload=data)

    def update_resource(self, resource_id: int, data: Dict[str, Any]) -> Dict[str, Any]:
        return self._request('PATCH', f'/resources/{resource_id}', payload=data)

    def delete_resource(self, resource_id: int) -> None:
        self._request('DELETE', f'/resources/{resource_id}')

